module dma_controller(
    input clk,
    input rst,
    input start,
    input [15:0] src_addr,
    input [15:0] dest_addr,
    input [7:0] transfer_size,
    output reg done
);
    reg [7:0] remaining_bytes;
    reg transferring;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            remaining_bytes <= 8'b0;
            done <= 0;
            transferring <= 0;
        end else if (start && !transferring) begin
            transferring <= 1;
            remaining_bytes <= transfer_size;
            done <= 0;
        end else if (transferring) begin
            if (remaining_bytes > 0) begin
                remaining_bytes <= remaining_bytes - 1;
            end else begin
                transferring <= 0;
                done <= 1;
            end
        end
    end
endmodule
